module RefModule(
    input wire clk,
    input wire rst,
    input wire dir,
    output reg [5:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (rst) begin
            count <= 6'b000000;
        end else if (dir) begin
            count <= count + 1;
        end else begin
            count <= count - 1;
        end
    end
endmodule
